export function hero_title(p?: Record<string, string | number>): string { return _t(["Das Betriebssystem, das in Ihrem Browser läuft","The operating system that runs in your browser","在您的浏览器中运行的操作系统","Операционная система, которая работает в вашем браузере"], p); }
export function hero_subtitle(p?: Record<string, string | number>): string { return _t(["Aufgebaut auf Rust WASM-Modulen und einer NixOS-inspirierten Architektur. Keine Hardware. Keine Treiber. Keine OS-Fehler. By design. Passt sich Ihrem Gerät an: auf Smartphones, Tablets und Desktops gleichermaßen zuhause.","Built on Rust WASM modules and a NixOS-inspired architecture. No hardware. No drivers. No OS errors. By design. Adapts to your device: feels at home on phones, tablets, and desktops alike.","基于 Rust WASM 模块和受 NixOS 启发的架构构建。无需硬件。无需驱动程序。没有系统错误。源于设计。适应您的设备：在手机、平板电脑和桌面上都如鱼得水。","Построена на модулях Rust WASM и архитектуре, вдохновлённой NixOS. Никакого железа. Никаких драйверов. Никаких ошибок ОС. По задумке. Адаптируется к вашему устройству: одинаково удобна на смартфонах, планшетах и десктопах."], p); }
export function core_promise_label(p?: Record<string, string | number>): string { return _t(["Das Kernversprechen","The core promise","核心承诺","Главное обещание"], p); }
export function zero_errors_title(p?: Record<string, string | number>): string { return _t(["Das erste OS, das nicht versagen kann.","The first OS that cannot fail.","第一个不会崩溃的操作系统。","Первая ОС, которая не может сломаться."], p); }
export function zero_errors_desc(p?: Record<string, string | number>): string { return _t(["Traditionelle Betriebssysteme versagen, weil sie von Hardware, Treibern und veränderbarem Zustand abhängen. RizinOS eliminiert alle drei. Der Betrieb im Browser bedeutet keine Hardwareabstraktionen, die brechen können, keine Treiberkonflikte und keinen Systemzustand, der korrumpiert werden kann.","Traditional operating systems fail because they depend on hardware, drivers, and mutable state. RizinOS eliminates all three. Running in the browser means no hardware abstractions to break, no drivers to conflict, and no system state to corrupt.","传统操作系统会崩溃，因为它们依赖于硬件、驱动程序和可变状态。RizinOS 消除了这三者。在浏览器中运行意味着没有可能损坏的硬件抽象层，没有驱动冲突，也没有可能损坏的系统状态。","Традиционные операционные системы дают сбои, потому что зависят от железа, драйверов и изменяемого состояния. RizinOS устраняет все три. Работа в браузере означает отсутствие аппаратных абстракций, которые могут сломаться, конфликтов драйверов и системного состояния, которое может быть нарушено."], p); }
export function hardware_independent_title(p?: Record<string, string | number>): string { return _t(["Hardwareunabhängig","Hardware-independent","硬件独立","Независимость от железа"], p); }
export function hardware_independent_desc(p?: Record<string, string | number>): string { return _t(["Keine Gerätetreiber. Keine Hardwarekonflikte. Der Browser ist die Hardwareschicht, und Browser sind darin ausgezeichnet.","No device drivers. No hardware conflicts. The browser is the hardware layer, and browsers are extremely good at that job.","无需设备驱动程序。无硬件冲突。浏览器就是硬件层，而浏览器非常擅长这项工作。","Никаких драйверов устройств. Никаких аппаратных конфликтов. Браузер — это аппаратный слой, и браузеры справляются с этой задачей отлично."], p); }
export function declarative_config_title(p?: Record<string, string | number>): string { return _t(["Deklarative Konfiguration","Declarative configuration","声明式配置","Декларативная конфигурация"], p); }
export function declarative_config_desc(p?: Record<string, string | number>): string { return _t(["Jede Systemeinstellung ist versioniert und reproduzierbar. Keine Konfigurationsabweichungen zwischen Umgebungen, niemals.","Every system setting is version-controlled and reproducible. No configuration drift between environments, ever.","每个系统设置都经过版本控制且可重现。环境之间永远不会出现配置漂移。","Каждая настройка системы версионирована и воспроизводима. Никаких расхождений конфигурации между средами — никогда."], p); }
export function atomic_updates_title(p?: Record<string, string | number>): string { return _t(["Atomare Updates","Atomic updates","原子更新","Атомарные обновления"], p); }
export function atomic_updates_desc(p?: Record<string, string | number>): string { return _t(["Systemupdates werden atomar angewendet oder gar nicht. Fehlgeschlagene Updates werden automatisch zurückgerollt. Sie können jede Änderung jederzeit rückgängig machen.","System updates apply atomically or not at all. Failed updates roll back automatically. You can undo any change, any time.","系统更新要么完整应用，要么根本不应用。失败的更新会自动回滚。您可以随时撤销任何更改。","Обновления системы применяются атомарно или не применяются вовсе. Неудачные обновления откатываются автоматически. Вы можете отменить любое изменение в любое время."], p); }
