export function feature_rust_wasm_desc(p?: Record<string, string | number>): string { return _t(["Kern-OS-Module in Rust geschrieben, zu WebAssembly kompiliert. Nahezu native Leistung, vollständig im Browser.","Core OS modules written in Rust, compiled to WebAssembly. Near-native performance, entirely in the browser.","核心操作系统模块用 Rust 编写，编译为 WebAssembly。近乎原生的性能，完全在浏览器中运行。","Основные модули ОС написаны на Rust и скомпилированы в WebAssembly. Производительность, близкая к нативной, полностью в браузере."], p); }
