export function feature_nixos_desc(p?: Record<string, string | number>): string { return _t(["Deklarative, versionierte Systemkonfiguration. Jede Änderung jederzeit zurückrollen.","Declarative, version-controlled system configuration. Roll back any change at any time.","声明式、版本控制的系统配置。随时回滚任何更改。","Декларативная, версионированная конфигурация системы. Откат любого изменения в любое время."], p); }
export function feature_encryption_title(p?: Record<string, string | number>): string { return _t(["Clientseitige Verschlüsselung","Client-Side Encryption","客户端加密","Шифрование на стороне клиента"], p); }
export function feature_encryption_desc(p?: Record<string, string | number>): string { return _t(["Alle Daten werden verschlüsselt, bevor sie Ihr Gerät verlassen. Der Server sieht niemals Ihren Klartext.","All storage is encrypted before it leaves your device. The server never sees your plaintext.","所有存储在离开您的设备之前都经过加密。服务器永远看不到您的明文。","Все данные шифруются до того, как покидают ваше устройство. Сервер никогда не видит открытый текст."], p); }
export function feature_instant_title(p?: Record<string, string | number>): string { return _t(["Sofortstart","Instant Start","即时启动","Мгновенный старт"], p); }
export function feature_instant_desc(p?: Record<string, string | number>): string { return _t(["Kein POST. Keine Treiber. Keine Ladezeiten. Öffnen Sie einen Tab - Ihr OS ist da, genau wie Sie es verlassen haben.","No POST. No drivers. No loading. Open a tab and your OS is there, exactly as you left it.","无 POST。无驱动程序。无加载。打开标签页，您的操作系统就在那里，与您离开时完全相同。","Никаких POST-запросов. Никаких драйверов. Никакой загрузки. Откройте вкладку - и ваша ОС уже там, точно так, как вы её оставили."], p); }
