export function bg_app_desc(p?: Record<string, string | number>): string { return _t(["Installieren Sie die optionale Hintergrund-App, um RizinOS mit Ihrem Gerät zu verbinden. Dateisynchronisation, Peripheriezugriff und native Benachrichtigungen, ohne die Browser-First-Architektur aufzugeben.","Install the optional Background App to bridge RizinOS with your device. File sync, peripheral access, and native notifications, without giving up the browser-first architecture.","安装可选的后台应用，将 RizinOS 与您的设备连接起来。文件同步、外设访问和本地通知，同时保持浏览器优先架构。","Установите опциональное фоновое приложение для связи RizinOS с вашим устройством. Синхронизация файлов, доступ к периферии и нативные уведомления - без отказа от браузерной архитектуры."], p); }
