export function sync_push_notif(p?: Record<string, string | number>): string { return _t(["Push-Benachrichtigungen auch wenn der Browser-Tab geschlossen ist","Push notifications even when the browser tab is closed","即使关闭浏览器标签页也能收到推送通知","Push-уведомления даже при закрытой вкладке браузера"], p); }
