export function arch_label(p?: Record<string, string | number>): string { return _t(["Architektur","Architecture","架构","Архитектура"], p); }
export function arch_title(p?: Record<string, string | number>): string { return _t(["Saubere Schichten, keine Abkürzungen.","Clean layers, no shortcuts.","清晰的层次，没有捷径。","Чистые слои, никаких компромиссов."], p); }
export function arch_desc(p?: Record<string, string | number>): string { return _t(["Rust-Module werden zu WASM kompiliert und als Kernel-Schicht ausgeführt. SvelteKit steuert die System-Shell. Jede App ist ein isolierter WASM-Prozess mit eigenem Speicherbereich und typisiertem IPC zum OS. Nichts wird implizit geteilt.","Rust modules compile to WASM and run as the kernel layer. SvelteKit drives the system shell. Each app is an isolated WASM process with its own memory space and typed IPC to the OS. Nothing is shared implicitly.","Rust 模块编译为 WASM 并作为内核层运行。SvelteKit 驱动系统外壳。每个应用程序都是一个独立的 WASM 进程，具有自己的内存空间和到操作系统的类型化 IPC。没有任何内容是隐式共享的。","Модули Rust компилируются в WASM и выполняются как уровень ядра. SvelteKit управляет системной оболочкой. Каждое приложение — изолированный WASM-процесс с собственным пространством памяти и типизированным IPC к ОС. Ничего не передаётся неявно."], p); }
export function arch_ipc_note(p?: Record<string, string | number>): string { return _t(["Alle Schichten kommunizieren über typisierte IPC-Schnittstellen","All layers communicate through typed IPC interfaces","所有层通过类型化 IPC 接口进行通信","Все слои общаются через типизированные интерфейсы IPC"], p); }
export function applications_label(p?: Record<string, string | number>): string { return _t(["Anwendungen","Applications","应用程序","Приложения"], p); }
export function apps_title(p?: Record<string, string | number>): string { return _t(["Eine vollständige Suite. Eingebaut.","A full suite. Built in.","完整套件，内置集成。","Полный набор. Встроенный."], p); }
export function apps_desc(p?: Record<string, string | number>): string { return _t(["Jede App teilt ein einheitliches Berechtigungsmodell, Dateiprotokoll und Design-System. Sie sind OS-Bürger, keine Plugins.","Every app shares a unified permission model, file protocol, and design system. They are OS citizens, not plugins.","每个应用程序共享统一的权限模型、文件协议和设计系统。它们是操作系统的一等公民，而非插件。","Каждое приложение использует единую модель разрешений, файловый протокол и дизайн-систему. Они — граждане ОС, а не плагины."], p); }
export function apps_roadmap(p?: Record<string, string | number>): string { return _t(["+ Minecraft-Integration, KI-Assistent, Stripe-Zahlungen, Videoanrufe in der Roadmap","+ Minecraft integration, AI assistant, Stripe payments, video calling in the roadmap","+ Minecraft 集成、AI 助手、Stripe 支付、视频通话已在路线图中","+ Интеграция с Minecraft, ИИ-ассистент, платежи Stripe, видеозвонки в roadmap"], p); }
export function cta_title(p?: Record<string, string | number>): string { return _t(["Ihr OS wartet. Öffnen Sie einen Tab.","Your OS is waiting. Open a tab.","您的操作系统在等待。打开一个标签页。","Ваша ОС ждёт. Откройте вкладку."], p); }
export function cta_desc(p?: Record<string, string | number>): string { return _t(["Keine Downloads. Kein Setup. Funktioniert auf jedem Gerät, jeder Bildschirmgröße, jedem Browser.","No downloads. No setup. Works on any device, any screen size, any browser.","无需下载。无需设置。适用于任何设备、任何屏幕尺寸、任何浏览器。","Без загрузок. Без настройки. Работает на любом устройстве, любом размере экрана, в любом браузере."], p); }
export function cta_button(p?: Record<string, string | number>): string { return _t(["Konto erstellen","Create your account","创建您的账户","Создать аккаунт"], p); }
export function cta_note(p?: Record<string, string | number>): string { return _t(["Dauerhaft kostenlos - Keine Kreditkarte - 10 GB Cloud-Speicher inklusive","Free tier forever - No credit card - 10 GB cloud storage included","永久免费 - 无需信用卡 - 包含 10 GB 云存储","Бесплатно навсегда - Без кредитной карты - 10 ГБ облачного хранилища включено"], p); }
